  void tech_map_impl<Ntk, CutSize, CutData, NInputs, Configuration>::match_phase(node<Ntk> const &n, uint8_t phase) {
    // Maintain multiple solutions to avoid local optima
    const int POPULATION_SIZE = 5;
    struct Solution {
        double arrival;
        double area_flow;
        float area;
        uint32_t size;
        uint8_t cut;
        uint8_t phase;
    };
    Solution best_solutions[POPULATION_SIZE];

    // Initialize population
    for (int i = 0; i < POPULATION_SIZE; i++) {
        best_solutions[i] = {
            std::numeric_limits<double>::max(),
            std::numeric_limits<double>::max(),
            std::numeric_limits<float>::max(),
            UINT32_MAX,
            0u,
            0u
        };
    }
    uint8_t cut_index = 0u;
    auto index = ntk.node_to_index(n);

    auto &node_data = node_match[index];
    auto &cut_matches = matches[index];
    supergate<NInputs> const *best_supergate = node_data.best_supergate[phase];

    /* recompute best match info */
    if (best_supergate != nullptr) {
      auto const &cut = cuts.cuts(index)[node_data.best_cut[phase]];

      best_phase = node_data.phase[phase];
      best_arrival = 0.0f;
      best_area_flow = best_supergate->area + cut_leaves_flow(cut, n, phase);
      best_area = best_supergate->area;
      best_cut = node_data.best_cut[phase];
      best_size = cut.size();

      auto ctr = 0u;
      for (auto l : cut) {
        double arrival_pin = node_match[l].arrival[(best_phase >> ctr) & 1] + best_supergate->tdelay[ctr];
        best_arrival = std::max(best_arrival, arrival_pin);
        ++ctr;
      }
    }

    /* Calculate adaptive weights for probabilistic selection */
    double total_weight = 0.0;
    static double exploration_factor = 1.0;

    for (auto &cut : cuts.cuts(index)) {
        // Favor smaller cuts but allow exploration of larger ones
        total_weight += pow(1.0 / (cut->size() + 1), exploration_factor);
    }

    /* foreach cut with adaptive probabilistic selection */
    for (auto &cut : cuts.cuts(index)) {
        // Adaptive probability-based selection
        double cut_weight = pow(1.0 / (cut->size() + 1), exploration_factor) / total_weight;
        if (rand()/(double)RAND_MAX > cut_weight) continue;

        // Adaptively adjust exploration based on progress
        static double last_improvement = std::numeric_limits<double>::max();
        if (best_solution.arrival < last_improvement - epsilon) {
            // If improving, allow more exploration
            exploration_factor = std::min(2.0, exploration_factor * 1.01);
            last_improvement = best_solution.arrival;
        } else {
            // If stagnating, reduce exploration
            exploration_factor = std::max(0.3, exploration_factor * 0.99);
        }
      /* trivial cuts or not matched cuts */
      if ((*cut)->data.ignore) {
        ++cut_index;
        continue;
      }

      auto const &supergates = cut_matches[(*cut)->data.match_index].supergates;
      auto const negation = cut_matches[(*cut)->data.match_index].negations[phase];

      if (supergates[phase] == nullptr) {
        ++cut_index;
        continue;
      }

      /* match each gate and take the best one */
      for (auto const &gate : *supergates[phase]) {
        uint8_t gate_polarity = gate.polarity ^ negation;
        node_data.phase[phase] = gate_polarity;
        double area_local = gate.area + cut_leaves_flow(*cut, n, phase);
        double worst_arrival = 0.0f;

        auto ctr = 0u;
        for (auto l : *cut) {
          double arrival_pin = node_match[l].arrival[(gate_polarity >> ctr) & 1] + gate.tdelay[ctr];
          worst_arrival = std::max(worst_arrival, arrival_pin);
          ++ctr;
        }

        if constexpr (DO_AREA) {
          if (worst_arrival > node_data.required[phase] + epsilon)
            continue;
        }

        // Check against all solutions in population
        for (int i = 0; i < POPULATION_SIZE; i++) {
            if (compare_map<DO_AREA>(worst_arrival, best_solutions[i].arrival, 
                                   area_local, best_solutions[i].area_flow, 
                                   cut->size(), best_solutions[i].size)) {
                best_solutions[i] = {
                    worst_arrival,
                    area_local,
                    gate.area,
                    cut->size(),
                    cut_index,
                    gate_polarity
                };
                break;
            }
        }
      }

      ++cut_index;
    }

    // Select best solution from population with occasional mutation
    static int stagnation_counter = 0;
    static double last_best = std::numeric_limits<double>::max();

    Solution best_solution = best_solutions[0];
    for (int i = 1; i < POPULATION_SIZE; i++) {
        if (compare_map<DO_AREA>(best_solutions[i].arrival, best_solution.arrival,
                               best_solutions[i].area_flow, best_solution.area_flow,
                               best_solutions[i].size, best_solution.size)) {
            best_solution = best_solutions[i];
        }
    }

    // Adaptive temperature control for exploration
    static double temperature = 1.0;
    static double last_best_area = std::numeric_limits<double>::max();
    static double last_improvement = std::numeric_limits<double>::max();

    // Update temperature based on progress
    if (best_solution.arrival < last_improvement - epsilon) {
        temperature *= 0.9; // Cool down when improving
    } else {
        temperature = std::min(1.0, temperature * 1.1); // Heat up when stuck
    }
    last_improvement = best_solution.arrival;
    if (abs(best_solution.arrival - last_best) < epsilon && 
        abs(best_solution.area_flow - last_best_area) < epsilon) {
        stagnation_counter++;
        if (stagnation_counter > 5) { // More sensitive to stagnation
            // Mutate worst solution in population
            int worst_idx = 0;
            for (int i = 1; i < POPULATION_SIZE; i++) {
                if (!compare_map<DO_AREA>(best_solutions[i].arrival, best_solutions[worst_idx].arrival,
                                        best_solutions[i].area_flow, best_solutions[worst_idx].area_flow,
                                        best_solutions[i].size, best_solutions[worst_idx].size)) {
                    worst_idx = i;
                }
            }
            // More aggressive mutation with random jumps
            best_solutions[worst_idx] = {
                best_solution.arrival * (0.8 + 0.4 * rand()/(double)RAND_MAX),
                best_solution.area_flow * (0.8 + 0.4 * rand()/(double)RAND_MAX),
                best_solution.area * (0.8 + 0.4 * rand()/(double)RAND_MAX),
                std::min(best_solution.size + (rand() % 3), UINT32_MAX),
                (rand() % cuts.cuts(index).size()),
                rand() % 2
            };
            stagnation_counter = 0;
        }
    } else {
        stagnation_counter = 0;
    }
    last_best = best_solution.arrival;

    node_data.flows[phase] = best_solution.area_flow;
    node_data.arrival[phase] = best_solution.arrival;
    node_data.area[phase] = best_solution.area;
    node_data.best_cut[phase] = best_solution.cut;
    node_data.phase[phase] = best_solution.phase;
  }

